import fs from 'node:fs';
import path from 'node:path';
import { globSync } from 'glob';
import { decodeHTML } from 'entities';

/**
 * Script to post-process Markdown files generated by xmldoc2md.
 * Adds the required 'title' Frontmatter for Starlight compatibility.
 */

// 1. Locate all generated Markdown files
const files = globSync('src/content/docs/sdk-cs/**/*.md');

if (files.length === 0) {
  console.log('⚠️ No files found. Ensure xmldoc2md has run correctly.');
  process.exit(0);
}

files.forEach((file) => {
  const originalRawContent = fs.readFileSync(file, 'utf-8');
  
  // 1. Decode HTML entities (e.g., &lt; -> <)
  let content = decodeHTML(originalRawContent);

  // 1.1 Remove "- " from numbered lists like "1. - "
  content = content.replace(/^(\s*\d+\.) - /gm, '$1 ');

  // 1.2 Remove "Type Parameters" section if it only contains bare type names (T0, T1, V, etc.)
  content = content.replace(/^#### Type Parameters\r?\n\r?\n(?:`[A-Z0-9]+`<br>\r?\n(?:\r?\n)?)+(?=(?:####|Inheritance|Implements|Attributes|\[Object\]|$))/gm, '');

  let finalContent = '';

  // Skip adding frontmatter if file already has it
  if (content.startsWith('---')) {
    // Even if we skip, we still ensure the file ends with a single blank line
    finalContent = content.trimEnd() + '\n';
  } else {
    // 2. Extract the first H1 (# ) to use as the official page title
    // Use a simple state machine to avoid picking up # inside code blocks
    const lines = content.split(/\r?\n/);
    let title = path.basename(file, '.md'); // Fallback title based on filename
    let h1Index = -1;
    let inCodeBlock = false;

    for (let i = 0; i < lines.length; i++) {
      // Toggle code block state
      if (lines[i].trimStart().startsWith('```')) {
        inCodeBlock = !inCodeBlock;
        continue;
      }

      // If not in code block, look for the first H1
      if (!inCodeBlock && lines[i].startsWith('# ')) {
        h1Index = i;
        break;
      }
    }
    
    if (h1Index !== -1) {
      title = lines[h1Index].slice(2).trim();
      // Remove the H1 from the body to avoid duplicate titles in Starlight
      lines.splice(h1Index, 1);
    }

    // 3. Construct the Frontmatter
    // Use single quotes and escape internal single quotes for better YAML safety
    const safeTitle = title.replace(/'/g, "''");
    const frontmatter = `---\ntitle: '${safeTitle}'\n---\n\n`;
    
    // 4. Construct final content
    // .trim() removes leading/trailing whitespace, then we add exactly one newline
    finalContent = frontmatter + lines.join('\n').trim() + '\n';
  }

  // 5. Idempotent write: Only write if content has changed
  if (finalContent !== originalRawContent) {
    fs.writeFileSync(file, finalContent);
    console.log(`Processed: ${file}${finalContent.length !== originalRawContent.length ? ` (Size: ${originalRawContent.length} -> ${finalContent.length})` : ''}`);
  }
});

console.log(`\n🎉 Successfully processed ${files.length} files for Starlight.`);
